const controller={};import publisherLayer from"./publisher.layer.js";import{io}from"../socket/io.js";controller.setPublisher=(async(r,e)=>{try{await publisherLayer.createPublication(r.body);e.status(200).send("ok")}catch(r){return console.log(r),e.status(500).send("Error server internal.")}}),controller.getAllPublisher=(async(r,e)=>{try{const r=await publisherLayer.getAllPublishe();return e.json(r)}catch(r){return console.log(r),e.status(500).send("Error server internal.")}}),controller.getPublisherAndArticle=(async(r,e)=>{try{const t=r.params.id,s=await publisherLayer.getPublisherAndArticle(t);return e.json(s)}catch(r){return console.log(r),e.status(500).send("Error server internal.")}}),controller.getPublisherPaginate=(async(r,e)=>{try{const t=r.params.page,s=r.params.items,a=await publisherLayer.getPublisherPaginate(t,s);return e.json(a)}catch(r){return console.log(r),e.status(500).send("Error server internal.")}}),controller.getPublisherSearch=(async(r,e)=>{try{const t=r.params.search,s=r.params.page,a=r.params.numberItems,l=await publisherLayer.searchPublisher(t,s,a);return e.json(l)}catch(r){console.log(r),e.status(500)}});export default controller;